// src/components/Navbar.jsx
import React from "react";
import { AppBar, Toolbar, Typography, Button, Box } from "@mui/material";
import { Link, useLocation } from "react-router-dom";
import LocalHospitalIcon from "@mui/icons-material/LocalHospital";
import { useAuth } from "../context/AuthContext";

const Navbar = () => {
  const location = useLocation();
  const { currentUser, isAdmin, logout } = useAuth();

  const isAdminPath = location.pathname.startsWith("/admin");

  return (
    <AppBar position="sticky" sx={{ bgcolor: "#1976d2", boxShadow: 3 }}>
      <Toolbar>
        <Box
          sx={{ display: "flex", alignItems: "center", gap: 1.5, flexGrow: 1 }}
        >
          <LocalHospitalIcon sx={{ fontSize: 32 }} />
          <Typography
            variant="h6"
            component={Link}
            to="/"
            sx={{ color: "white", textDecoration: "none", fontWeight: 700 }}
          >
            Arogya Nepal
          </Typography>
        </Box>

        {/* Patient Navigation */}
        {!isAdminPath && (
          <>
            <Button color="inherit" component={Link} to="/">
              Hospitals
            </Button>
            {currentUser && (
              <Button color="inherit" component={Link} to="/patient">
                My Dashboard
              </Button>
            )}
          </>
        )}

        {/* Admin Navigation */}
        {isAdminPath && (
          <Button color="inherit" component={Link} to="/admin">
            Admin Dashboard
          </Button>
        )}

        {/* Auth Buttons */}
        <Box sx={{ ml: 2 }}>
          {isAdmin ? (
            <Button
              variant="outlined"
              color="inherit"
              onClick={logout}
              sx={{ borderColor: "white", color: "white" }}
            >
              Logout Admin
            </Button>
          ) : currentUser ? (
            <>
              <Button
                color="inherit"
                component={Link}
                to="/patient"
                sx={{ mr: 1 }}
              >
                {currentUser.fullName.split(" ")[0]}
              </Button>
              <Button
                variant="outlined"
                color="inherit"
                onClick={logout}
                sx={{ borderColor: "white", color: "white" }}
              >
                Logout
              </Button>
            </>
          ) : (
            <>
              <Button
                color="inherit"
                component={Link}
                to="/patient/login"
                sx={{ mr: 1 }}
              >
                Patient Login
              </Button>
              <Button
                variant="outlined"
                color="inherit"
                component={Link}
                to="/admin/login"
                sx={{ borderColor: "white", color: "white" }}
              >
                Admin Login
              </Button>
            </>
          )}
        </Box>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
